LineComment.Text:
// Zbocze narastające Power
IF "HMI_Central_Shifter".CS_Power AND NOT #prevPower THEN
    "HMI_Central_Shifter".CS_Reset := TRUE;
    #tPowerCheck(IN := TRUE,
                 PT := T#2S);   // uruchom 2-sekundowy timer

ELSIF "HMI_Central_Shifter".CS_Power AND "HMI_Central_Shifter".CS_Reset THEN
    // Po jednym cyklu reset wyłącz
    "HMI_Central_Shifter".CS_Reset := FALSE;
END_IF;

// Aktualizacja timera (musi być poza IF, żeby działał ciągle)
#tPowerCheck.IN := "HMI_Central_Shifter".CS_Power;

// Główna logika sprawdzania statusów
IF "HMI_Central_Shifter".CS_Power AND #tPowerCheck.Q THEN
    // Sprawdź statusy dopiero po upływie czasu (gdy napędy zdążą się uruchomić)
    IF NOT (
        #MC_POWER_CS_PL.Status AND
        #MC_POWER_CS_PP.Status AND
        #MC_POWER_CS_TL.Status AND
        #MC_POWER_CS_TP.Status
        ) THEN
        // Gdy któryś napęd nie ma Power po czasie → wyłącz
        "HMI_Central_Shifter".CS_Power := FALSE;
    END_IF;

ELSIF NOT "HMI_Central_Shifter".CS_Power THEN
    // Power OFF → reset timera i czyszczenie
    "HMI_Central_Shifter".CS_Reset := FALSE;
    #tPowerCheck.IN := FALSE;
END_IF;

IF #MC_POWER_CS_PP.Status AND
    #MC_POWER_CS_TL.Status AND
    #MC_POWER_CS_TP.Status THEN
    #Status_Power_Synch := 1;
ELSE
    #Status_Power_Synch := 0;
END_IF;

// Zapamiętaj poprzedni stan Power
#prevPower := "HMI_Central_Shifter".CS_Power;

"CS_Drive_PP_Actor_Interface_TorqueDataAddressOut".UpperTorqueLimit := 16#4000;
"CS_Drive_PP_Actor_Interface_TorqueDataAddressOut".LowerTorqueLimit := -16#4000;

IF #MC_MOVEJOG_CS_Virtual.JogForward THEN
    "CS_Drive_PL_Actor_Interface_TorqueDataAddressOut".UpperTorqueLimit := "CS_Drive_PP_Actor_Interface_TorqueDataAddressIn".ActualTorque;

    "CS_Drive_PL_Actor_Interface_TorqueDataAddressOut".LowerTorqueLimit := -1* "CS_Drive_PP_Actor_Interface_TorqueDataAddressIn".ActualTorque;

ELSIF #MC_MOVEJOG_CS_Virtual.JogBackward THEN
    "CS_Drive_PL_Actor_Interface_TorqueDataAddressOut".UpperTorqueLimit := -1*"CS_Drive_PP_Actor_Interface_TorqueDataAddressIn".ActualTorque;

    "CS_Drive_PL_Actor_Interface_TorqueDataAddressOut".LowerTorqueLimit :=  "CS_Drive_PP_Actor_Interface_TorqueDataAddressIn".ActualTorque;

    ;
ELSE
    "CS_Drive_PL_Actor_Interface_TorqueDataAddressOut".UpperTorqueLimit := 16#4000;

    "CS_Drive_PL_Actor_Interface_TorqueDataAddressOut".LowerTorqueLimit := - 16#4000;
END_IF;
